package assignments;

public class Day2_Assignments {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		float variable = 97.8f;
		System.out.println("Float Value :" + variable);
		
		double variableDouble =variable;
		System.out.println("Converted to Double :"+ variableDouble);
		
		int variableInt =(int)variable;
		System.out.println("Converted to int :"+ variableInt);
		
		char alpha = 'a';
		int value = alpha;
		System.out.println(value);
		
		int number = 97;
		char asciiChar =(char)number;
		System.out.println(asciiChar);
		
		
		
		
	}

}
